package federation

import (
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/update"
)

// HandshakeResult is the outcome of validating a spoke's version handshake
// against the hub's own version + schema version.
type HandshakeResult struct {
	// Accept reports whether the registration should be accepted at all.
	Accept bool
	// Status is the SpokeStatus to record on accepted registrations:
	// StatusRegistered when fully compatible (heartbeat will move it to
	// StatusActive), or StatusDegraded when accepted-but-newer.
	Status SpokeStatus
	// Reason is a short, machine-readable code for the outcome — used as the
	// rejection reason on 4xx and as a degraded-status reason on accept.
	// Stable enum: "ok", "degraded_newer_minor",
	// "schema_mismatch", "ddx_major_mismatch", "missing_ddx_version",
	// "missing_schema_version", "invalid_ddx_version".
	Reason string
}

// Handshake validates a spoke's version handshake.
//
//   - schema_version must match the hub's schema version exactly. Anything
//     else is rejected ("schema_mismatch").
//   - ddx_version must parse as semver. Major version must match the hub.
//     A higher minor or patch on the spoke side accepts as StatusDegraded
//     ("degraded_newer_minor"). Equal-or-lower minors/patches accept as
//     StatusRegistered ("ok"). Mismatched majors are rejected
//     ("ddx_major_mismatch").
//
// Empty / unparseable inputs are rejected with descriptive reasons.
func Handshake(hubDDxVersion, hubSchemaVersion, spokeDDxVersion, spokeSchemaVersion string) HandshakeResult {
	if strings.TrimSpace(spokeSchemaVersion) == "" {
		return HandshakeResult{Reason: "missing_schema_version"}
	}
	if spokeSchemaVersion != hubSchemaVersion {
		return HandshakeResult{Reason: "schema_mismatch"}
	}
	if strings.TrimSpace(spokeDDxVersion) == "" {
		return HandshakeResult{Reason: "missing_ddx_version"}
	}
	hubParts, err := update.ParseVersion(hubDDxVersion)
	if err != nil {
		return HandshakeResult{Reason: fmt.Sprintf("invalid_hub_ddx_version:%v", err)}
	}
	spokeParts, err := update.ParseVersion(spokeDDxVersion)
	if err != nil {
		return HandshakeResult{Reason: "invalid_ddx_version"}
	}
	if spokeParts[0] != hubParts[0] {
		return HandshakeResult{Reason: "ddx_major_mismatch"}
	}
	// Same major, compare minor.patch. Any newer minor or patch on the spoke
	// side is "compatible-but-newer" → degraded.
	newer := spokeParts[1] > hubParts[1] ||
		(spokeParts[1] == hubParts[1] && spokeParts[2] > hubParts[2])
	if newer {
		return HandshakeResult{Accept: true, Status: StatusDegraded, Reason: "degraded_newer_minor"}
	}
	return HandshakeResult{Accept: true, Status: StatusRegistered, Reason: "ok"}
}

---
package server

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// HubDefaultDDxVersion is the ddx_version the hub advertises when validating
// spoke handshakes. It is exposed as a field so tests and operators can pin
// the hub's view of "current ddx version" without rebuilding the binary.
const HubDefaultDDxVersion = "0.1.0"

// federationHub holds the per-server state for hub-mode federation: the
// in-memory registry, the disk path used to persist it, the warning logger
// (for plain-HTTP accepted registrations), and configuration knobs.
type federationHub struct {
	mu             sync.Mutex
	registry       *federation.FederationRegistry
	statePath      string // empty disables disk persistence
	allowPlainHTTP bool
	hubDDxVersion  string
	hubSchemaVer   string
	warnLog        func(format string, args ...any)
	warnings       []string // captured plain-HTTP warnings (test introspection)
	conflictsLog   []string // captured 409 conflict log lines (test introspection)
	now            func() time.Time
}

// EnableHubMode mounts the /api/federation/* routes on this server, switches
// the hub-mode flag on, and (best effort) loads the registry from disk so a
// hub restart can rebuild state from a prior session.
//
// Must be called before ListenAndServe / ListenAndServeTLS. Calling it more
// than once is a no-op after the first call.
//
// allowPlainHTTP relaxes the default ts-net/loopback peer policy on the
// federation routes — non-trusted peers are accepted, but each accepted
// registration emits a WARN log entry. This is the operator opt-out for
// federations spanning networks where ts-net is not viable.
func (s *Server) EnableHubMode(allowPlainHTTP bool) {
	if s.hub != nil {
		return
	}
	statePath, err := federation.DefaultStatePath()
	if err != nil {
		statePath = ""
	}
	var reg *federation.FederationRegistry
	if statePath != "" {
		if loaded, lerr := federation.LoadStateFrom(statePath); lerr == nil {
			reg = loaded
		}
	}
	if reg == nil {
		reg = federation.NewRegistry()
	}
	s.hub = &federationHub{
		registry:       reg,
		statePath:      statePath,
		allowPlainHTTP: allowPlainHTTP,
		hubDDxVersion:  HubDefaultDDxVersion,
		hubSchemaVer:   federation.CurrentSchemaVersion,
		warnLog:        func(format string, args ...any) { log.Printf("WARN: "+format, args...) },
		now:            time.Now,
	}
	s.HubMode = true

	gate := func(h http.HandlerFunc) http.HandlerFunc { return s.requireFederationTrusted(h) }
	s.route("POST /api/federation/register", gate(s.handleFederationRegister))
	s.route("POST /api/federation/heartbeat", gate(s.handleFederationHeartbeat))
	s.route("GET /api/federation/spokes", gate(s.handleFederationListSpokes))
	s.route("DELETE /api/federation/spokes/{id}", gate(s.handleFederationDeregister))
}

// HubFederationRegistrySnapshot returns a copy of the current registry, for
// tests and operator introspection.
func (s *Server) HubFederationRegistrySnapshot() *federation.FederationRegistry {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	out := federation.NewRegistry()
	out.SchemaVersion = s.hub.registry.SchemaVersion
	out.Spokes = append(out.Spokes, s.hub.registry.Spokes...)
	return out
}

// HubFederationWarnings returns plain-HTTP-accepted-registration WARN messages
// captured since the server started. Test-only helper.
func (s *Server) HubFederationWarnings() []string {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	return append([]string(nil), s.hub.warnings...)
}

// HubFederationConflicts returns 409 conflict log messages captured since the
// server started. Test-only helper.
func (s *Server) HubFederationConflicts() []string {
	if s.hub == nil {
		return nil
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	return append([]string(nil), s.hub.conflictsLog...)
}

// requireFederationTrusted enforces the federation-specific peer policy:
// loopback / ts-net peers are always accepted; non-trusted peers are accepted
// only when --federation-allow-plain-http is set. Distinct from
// requireTrusted so the AC-strict default doesn't depend on a global flag.
func (s *Server) requireFederationTrusted(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if isTrusted(r) {
			next(w, r)
			return
		}
		if s.hub != nil && s.hub.allowPlainHTTP {
			next(w, r)
			return
		}
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: ts-net or loopback peer required for /api/federation/* (use --federation-allow-plain-http to opt out)"})
	}
}

// federationRegisterRequest is the spoke→hub registration / re-registration
// payload. Identity = (NodeID, IdentityFingerprint). NodeID is the stable
// federation key; IdentityFingerprint distinguishes a re-registration of the
// same node from a duplicate-name conflict (different machine claiming an
// already-registered node_id).
type federationRegisterRequest struct {
	NodeID               string   `json:"node_id"`
	IdentityFingerprint  string   `json:"identity_fingerprint,omitempty"`
	Name                 string   `json:"name"`
	URL                  string   `json:"url"`
	DDxVersion           string   `json:"ddx_version"`
	SchemaVersion        string   `json:"schema_version"`
	GraphQLSchemaVersion string   `json:"graphql_schema_version,omitempty"`
	Capabilities         []string `json:"capabilities,omitempty"`
}

// federationRegisterResponse is sent on a successful (200/201) registration.
type federationRegisterResponse struct {
	NodeID string                 `json:"node_id"`
	Status federation.SpokeStatus `json:"status"`
	Reason string                 `json:"reason"`
	Spoke  federation.SpokeRecord `json:"spoke"`
}

// identityFingerprintKey is the SpokeRecord.Capabilities-adjacent slot we
// stash the fingerprint in. To keep the on-disk schema stable (B14.2 froze
// SpokeRecord shape), we encode it as a synthetic capability prefixed with
// "@identity:". Future schema versions can hoist it to a first-class field.
const identityFingerprintPrefix = "@identity:"

func setIdentityFingerprint(rec *federation.SpokeRecord, fp string) {
	cleaned := rec.Capabilities[:0]
	for _, c := range rec.Capabilities {
		if !strings.HasPrefix(c, identityFingerprintPrefix) {
			cleaned = append(cleaned, c)
		}
	}
	rec.Capabilities = cleaned
	if fp != "" {
		rec.Capabilities = append(rec.Capabilities, identityFingerprintPrefix+fp)
	}
}

func getIdentityFingerprint(rec federation.SpokeRecord) string {
	for _, c := range rec.Capabilities {
		if strings.HasPrefix(c, identityFingerprintPrefix) {
			return strings.TrimPrefix(c, identityFingerprintPrefix)
		}
	}
	return ""
}

func (s *Server) handleFederationRegister(w http.ResponseWriter, r *http.Request) {
	var req federationRegisterRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
		return
	}
	req.NodeID = strings.TrimSpace(req.NodeID)
	if req.NodeID == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
		return
	}
	if strings.TrimSpace(req.URL) == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "url required"})
		return
	}

	hs := federation.Handshake(s.hub.hubDDxVersion, s.hub.hubSchemaVer, req.DDxVersion, req.SchemaVersion)
	if !hs.Accept {
		writeJSON(w, http.StatusBadRequest, map[string]string{
			"error":  "version handshake failed",
			"reason": hs.Reason,
		})
		return
	}

	now := s.hub.now().UTC()

	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()

	if existing := s.hub.registry.FindSpoke(req.NodeID); existing != nil {
		existingFP := getIdentityFingerprint(*existing)
		// Identity conflict: a different machine claims an already-registered
		// node_id. Reject with 409 and log.
		if existingFP != "" && req.IdentityFingerprint != "" && existingFP != req.IdentityFingerprint {
			msg := fmt.Sprintf("federation: duplicate node_id %q from different identity (existing=%s, attempted=%s)",
				req.NodeID, existingFP, req.IdentityFingerprint)
			s.hub.conflictsLog = append(s.hub.conflictsLog, msg)
			s.hub.warnLog("%s", msg)
			writeJSON(w, http.StatusConflict, map[string]string{
				"error":  "node_id already registered to a different identity",
				"reason": "duplicate_node_id",
			})
			return
		}
	}

	rec := federation.SpokeRecord{
		NodeID:        req.NodeID,
		Name:          req.Name,
		URL:           req.URL,
		DDxVersion:    req.DDxVersion,
		SchemaVersion: req.SchemaVersion,

		SchemaVersion: req.SchemaVersion,
		Capabilities:  append([]string(nil), req.Capabilities...),
		RegisteredAt:  now,
		LastHeartbeat: time.Time{},
		Status:        hs.Status,
	}
	setIdentityFingerprint(&rec, req.IdentityFingerprint)
	if err := s.hub.registry.UpsertSpoke(rec); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
		return
	}
	s.persistFederationLocked()

	// Emit WARN if this registration was accepted via the plain-HTTP opt-out.
	if s.hub.allowPlainHTTP && !isTrusted(r) {
		msg := fmt.Sprintf("federation: accepted plain-HTTP registration node_id=%q url=%q from remote=%s",
			req.NodeID, req.URL, r.RemoteAddr)
		s.hub.warnings = append(s.hub.warnings, msg)
		s.hub.warnLog("%s", msg)
	}

	writeJSON(w, http.StatusOK, federationRegisterResponse{
		NodeID: rec.NodeID,
		Status: rec.Status,
		Reason: hs.Reason,
		Spoke:  rec,
	})
}

type federationHeartbeatRequest struct {
	NodeID string `json:"node_id"`
}

func (s *Server) handleFederationHeartbeat(w http.ResponseWriter, r *http.Request) {
	var req federationHeartbeatRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid json: " + err.Error()})
		return
	}
	req.NodeID = strings.TrimSpace(req.NodeID)
	if req.NodeID == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "node_id required"})
		return
	}

	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()

	rec := s.hub.registry.FindSpoke(req.NodeID)
	if rec == nil {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not registered"})
		return
	}
	now := s.hub.now().UTC()
	rec.LastHeartbeat = now
	// Heartbeat clears registered-on-first-seen and offline; preserves
	// degraded (set by the version handshake at registration time).
	if rec.Status == federation.StatusRegistered || rec.Status == federation.StatusOffline || rec.Status == federation.StatusStale {
		rec.Status = federation.StatusActive
	}
	s.persistFederationLocked()

	writeJSON(w, http.StatusOK, map[string]any{
		"node_id":        rec.NodeID,
		"status":         rec.Status,
		"last_heartbeat": rec.LastHeartbeat,
	})
}

func (s *Server) handleFederationListSpokes(w http.ResponseWriter, _ *http.Request) {
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	out := make([]federation.SpokeRecord, 0, len(s.hub.registry.Spokes))
	out = append(out, s.hub.registry.Spokes...)
	writeJSON(w, http.StatusOK, map[string]any{
		"schema_version": s.hub.registry.SchemaVersion,
		"spokes":         out,
	})
}

func (s *Server) handleFederationDeregister(w http.ResponseWriter, r *http.Request) {
	id := strings.TrimSpace(r.PathValue("id"))
	if id == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "id required"})
		return
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	if !s.hub.registry.RemoveSpoke(id) {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "spoke not found"})
		return
	}
	s.persistFederationLocked()
	writeJSON(w, http.StatusOK, map[string]string{"node_id": id, "status": "deregistered"})
}

// persistFederationLocked saves the registry to disk if a state path is set.
// Caller must hold s.hub.mu.
func (s *Server) persistFederationLocked() {
	if s.hub.statePath == "" {
		return
	}
	if err := federation.SaveStateTo(s.hub.statePath, s.hub.registry); err != nil {
		s.hub.warnLog("federation: persist state: %v", err)
	}
}

package federation

import (
	"bytes"
	"context"
	"crypto/rand"
	"crypto/tls"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"math/big"
	"net/http"
	"net/url"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// DefaultHeartbeatInterval is the nominal heartbeat cadence (ADR-007: 30s).
const DefaultHeartbeatInterval = 30 * time.Second

// DefaultHeartbeatJitterFraction is applied to the interval as ±jitter so
// independent spokes do not synchronize their beats against one hub. On the
// default 30s cadence this yields a ±5s window, matching ADR-007.
const DefaultHeartbeatJitterFraction = 5.0 / 30.0

// DefaultDeregisterTimeout caps the best-effort deregister request on shutdown.
const DefaultDeregisterTimeout = 2 * time.Second

// spokeStateFileName is the on-disk name for spoke-side state, used to detect
// URL changes across restarts so the spoke can re-register with a new URL.
const spokeStateFileName = "spoke-state.json"

// SpokeState is the per-spoke persistent state. It records the URL last
// advertised to the hub and the stable identity_fingerprint generated on
// first start, both so URL changes can be detected across restarts and so
// re-registration can prove identity to the hub.
type SpokeState struct {
	NodeID              string `json:"node_id"`
	IdentityFingerprint string `json:"identity_fingerprint"`
	LastURL             string `json:"last_url,omitempty"`
}

// DefaultSpokeStatePath returns ~/.local/share/ddx/spoke-state.json (XDG aware).
func DefaultSpokeStatePath() (string, error) {
	if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
		return filepath.Join(xdg, "ddx", spokeStateFileName), nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
	}
	return filepath.Join(home, ".local", "share", "ddx", spokeStateFileName), nil
}

// LoadSpokeState reads spoke state from path. Missing file → zero value.
func LoadSpokeState(path string) (*SpokeState, error) {
	data, err := os.ReadFile(path)
	if errors.Is(err, os.ErrNotExist) {
		return &SpokeState{}, nil
	}
	if err != nil {
		return nil, fmt.Errorf("federation: read spoke state: %w", err)
	}
	var st SpokeState
	if err := json.Unmarshal(data, &st); err != nil {
		// Corrupt file — start fresh; the caller will overwrite.
		return &SpokeState{}, nil
	}
	return &st, nil
}

// SaveSpokeState writes spoke state to path atomically (tmpfile+rename).
func SaveSpokeState(path string, st *SpokeState) error {
	if st == nil {
		return fmt.Errorf("federation: nil spoke state")
	}
	if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
		return fmt.Errorf("federation: mkdir: %w", err)
	}
	data, err := json.MarshalIndent(st, "", "  ")
	if err != nil {
		return err
	}
	tmp, err := os.CreateTemp(filepath.Dir(path), ".spoke-state-*.json.tmp")
	if err != nil {
		return err
	}
	tmpPath := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpPath)
		return err
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpPath)
		return err
	}
	if err := os.Chmod(tmpPath, fileMode); err != nil {
		_ = os.Remove(tmpPath)
		return err
	}
	return os.Rename(tmpPath, path)
}

// generateIdentityFingerprint returns a random 16-byte hex string. The
// fingerprint is generated once per node and persisted in spoke-state so a
// re-registration of the same node_id from the same machine is recognized
// as such (rather than rejected as a duplicate-identity conflict).
func generateIdentityFingerprint() string {
	var buf [16]byte
	if _, err := rand.Read(buf[:]); err != nil {
		// Fall back to a hostname-derived value; collisions here are
		// uninteresting because the hub's duplicate-id rejection only fires
		// on a *different* fingerprint claiming the same node_id.
		host, _ := os.Hostname()
		return "fp-" + host
	}
	return "fp-" + hex.EncodeToString(buf[:])
}

// SpokeConfig configures a Spoke lifecycle agent. URL is the spoke's own
// publicly-reachable URL (advertised to the hub); HubURL is the hub base URL
// (e.g. "https://hub.example:7743").
type SpokeConfig struct {
	NodeID               string
	Name                 string
	URL                  string
	HubURL               string
	DDxVersion           string
	SchemaVersion        string
	GraphQLSchemaVersion string
	Capabilities         []string

	// HeartbeatInterval defaults to DefaultHeartbeatInterval. Pass a small
	// value (e.g. 50ms) in tests.
	HeartbeatInterval time.Duration
	// HeartbeatJitterFraction is the ± jitter as a fraction of the interval
	// (e.g. 0.25 for ±25%). Defaults to DefaultHeartbeatJitterFraction.
	HeartbeatJitterFraction float64
	// DeregisterTimeout caps the best-effort deregister on shutdown.
	DeregisterTimeout time.Duration

	// StatePath is the disk path for spoke-state.json. Empty → DefaultSpokeStatePath.
	StatePath string
	// HTTPClient is used for hub requests. Nil → default client that accepts
	// self-signed certs (matches the server's auto-generated cert).
	HTTPClient *http.Client
	// Logger is used for warn/info; nil → log.Printf.
	Logger func(format string, args ...any)
}

// Spoke is the spoke-side lifecycle agent: register on Start, jittered
// heartbeat in the background, deregister best-effort on Shutdown.
type Spoke struct {
	cfg                 SpokeConfig
	identityFingerprint string

	mu              sync.Mutex
	statePath       string
	registered      bool
	stopped         chan struct{}
	stopOnce        sync.Once
	registeredCount int // test introspection
	heartbeatCount  int // test introspection
	urlChanged      bool
	urlChangedFrom  string
	hbErr           error
	logf            func(format string, args ...any)
}

// NewSpoke constructs a Spoke with defaults filled in. The spoke is not
// started until Start is called.
func NewSpoke(cfg SpokeConfig) (*Spoke, error) {
	if strings.TrimSpace(cfg.NodeID) == "" {
		return nil, fmt.Errorf("federation: spoke NodeID required")
	}
	if strings.TrimSpace(cfg.HubURL) == "" {
		return nil, fmt.Errorf("federation: spoke HubURL required")
	}
	if strings.TrimSpace(cfg.URL) == "" {
		return nil, fmt.Errorf("federation: spoke URL required")
	}
	if cfg.HeartbeatInterval <= 0 {
		cfg.HeartbeatInterval = DefaultHeartbeatInterval
	}
	if cfg.HeartbeatJitterFraction < 0 {
		cfg.HeartbeatJitterFraction = 0
	}
	if cfg.HeartbeatJitterFraction == 0 {
		cfg.HeartbeatJitterFraction = DefaultHeartbeatJitterFraction
	}
	if cfg.DeregisterTimeout <= 0 {
		cfg.DeregisterTimeout = DefaultDeregisterTimeout
	}
	if cfg.HTTPClient == nil {
		// Self-signed certs are the default for ddx-server, so the spoke
		// must skip cert verification by default. Operators wanting stricter
		// validation can pass a custom HTTPClient.
		cfg.HTTPClient = &http.Client{
			Timeout: 10 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		}
	}

	statePath := cfg.StatePath
	if statePath == "" {
		p, err := DefaultSpokeStatePath()
		if err != nil {
			return nil, err
		}
		statePath = p
	}

	logf := cfg.Logger
	if logf == nil {
		logf = func(format string, args ...any) { log.Printf(format, args...) }
	}

	st, err := LoadSpokeState(statePath)
	if err != nil {
		return nil, err
	}

	// Detect URL change between restarts.
	var urlChanged bool
	var prevURL string
	if st.NodeID == cfg.NodeID && st.LastURL != "" && st.LastURL != cfg.URL {
		urlChanged = true
		prevURL = st.LastURL
	}

	// Reuse fingerprint if it's for the same node_id; otherwise generate one.
	fp := st.IdentityFingerprint
	if fp == "" || st.NodeID != cfg.NodeID {
		fp = generateIdentityFingerprint()
	}

	s := &Spoke{
		cfg:                 cfg,
		identityFingerprint: fp,
		statePath:           statePath,
		stopped:             make(chan struct{}),
		urlChanged:          urlChanged,
		urlChangedFrom:      prevURL,
		logf:                logf,
	}
	return s, nil
}

// IdentityFingerprint returns the stable identity fingerprint persisted for
// this spoke. Useful for tests and operator diagnostics.
func (s *Spoke) IdentityFingerprint() string { return s.identityFingerprint }

---
func (s *Spoke) IdentityFingerprint() string { return s.identityFingerprint }

// URLChanged reports whether the spoke detected a URL change versus the
// last-known persisted state at startup time.
func (s *Spoke) URLChanged() bool { return s.urlChanged }

// PreviousURL returns the URL recorded in spoke-state on disk before this
// start (empty if none). Distinct from URLChanged so callers can log either.
func (s *Spoke) PreviousURL() string { return s.urlChangedFrom }

// HeartbeatCount returns the number of heartbeats sent (test introspection).
func (s *Spoke) HeartbeatCount() int {
	s.mu.Lock()
	defer s.mu.Unlock()
	return s.heartbeatCount
}

// RegisteredCount returns the number of register calls made (test introspection).
func (s *Spoke) RegisteredCount() int {
	s.mu.Lock()
	defer s.mu.Unlock()
	return s.registeredCount
}

// LastHeartbeatError returns the most recent heartbeat error or nil.
func (s *Spoke) LastHeartbeatError() error {
	s.mu.Lock()
	defer s.mu.Unlock()
	return s.hbErr
}

// Start performs the initial register-on-start and launches the jittered
// heartbeat goroutine. It returns the register error (if any); a successful
// Start means the hub accepted the registration.
//
// Start blocks until the initial registration completes (or fails). The
// heartbeat goroutine continues until Shutdown is called or ctx is canceled.
func (s *Spoke) Start(ctx context.Context) error {
	if err := s.register(ctx); err != nil {
		return err
	}
	// Persist current URL so the next start can detect a URL change.
	_ = SaveSpokeState(s.statePath, &SpokeState{
		NodeID:              s.cfg.NodeID,
		IdentityFingerprint: s.identityFingerprint,
		LastURL:             s.cfg.URL,
	})
	go s.heartbeatLoop(ctx)
	return nil
}

// Shutdown stops the heartbeat loop and sends a best-effort deregister.
// Safe to call multiple times. Always returns nil — deregister failures are
// logged but not surfaced (the hub may legitimately be down).
func (s *Spoke) Shutdown(ctx context.Context) error {
	s.stopOnce.Do(func() { close(s.stopped) })

	// Best-effort deregister with a bounded timeout so a dead hub does not
	// stall shutdown.
	dctx, cancel := context.WithTimeout(ctx, s.cfg.DeregisterTimeout)
	defer cancel()
	if err := s.deregister(dctx); err != nil {
		s.logf("federation: deregister best-effort failed: %v", err)
	}
	return nil
}

// register POSTs /api/federation/register to the hub.
func (s *Spoke) register(ctx context.Context) error {
	body := federationRegisterRequest{
		NodeID:               s.cfg.NodeID,
		IdentityFingerprint:  s.identityFingerprint,
		Name:                 s.cfg.Name,
		URL:                  s.cfg.URL,
		DDxVersion:           s.cfg.DDxVersion,
		SchemaVersion:        s.cfg.SchemaVersion,
		GraphQLSchemaVersion: s.cfg.GraphQLSchemaVersion,
		Capabilities:         append([]string(nil), s.cfg.Capabilities...),
	}
	resp, err := s.postJSON(ctx, "/api/federation/register", body)
	if err != nil {
		return err
	}
	defer func() { _ = resp.Body.Close() }()
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		buf, _ := io.ReadAll(resp.Body)
		return fmt.Errorf("federation register: hub returned %d: %s", resp.StatusCode, string(buf))
	}
	s.mu.Lock()
	s.registered = true
	s.registeredCount++
	s.mu.Unlock()
	return nil
}

// deregister DELETEs /api/federation/spokes/<id>.
func (s *Spoke) deregister(ctx context.Context) error {
	u, err := s.hubURL("/api/federation/spokes/" + url.PathEscape(s.cfg.NodeID))
	if err != nil {
		return err
	}
	req, err := http.NewRequestWithContext(ctx, http.MethodDelete, u, nil)
	if err != nil {
		return err
	}
	resp, err := s.cfg.HTTPClient.Do(req)
	if err != nil {
		return err
	}
	defer func() { _ = resp.Body.Close() }()
	_, _ = io.Copy(io.Discard, resp.Body)
	// 404 is fine — nothing to deregister.
	if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusNotFound {
		return fmt.Errorf("federation deregister: hub returned %d", resp.StatusCode)
	}
	return nil
}

// heartbeat POSTs /api/federation/heartbeat.
func (s *Spoke) heartbeat(ctx context.Context) error {
	body := map[string]string{"node_id": s.cfg.NodeID}
	resp, err := s.postJSON(ctx, "/api/federation/heartbeat", body)
	if err != nil {
		return err
	}
	defer func() { _ = resp.Body.Close() }()
	_, _ = io.Copy(io.Discard, resp.Body)
	if resp.StatusCode == http.StatusNotFound {
		// Hub forgot us — re-register.
		s.logf("federation: hub returned 404 on heartbeat; re-registering")
		return s.register(ctx)
	}
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return fmt.Errorf("federation heartbeat: hub returned %d", resp.StatusCode)
	}
	return nil
}

// heartbeatLoop runs until ctx is canceled or Shutdown is called. Sleeps for
// HeartbeatInterval ± jitter between beats.
func (s *Spoke) heartbeatLoop(ctx context.Context) {
	for {
		d := s.nextHeartbeatDelay()
		select {
		case <-ctx.Done():
			return
		case <-s.stopped:
			return
		case <-time.After(d):
		}
		if err := s.heartbeat(ctx); err != nil {
			s.mu.Lock()
			s.hbErr = err
			s.mu.Unlock()
			s.logf("federation: heartbeat failed: %v", err)
		} else {
			s.mu.Lock()
			s.hbErr = nil
			s.heartbeatCount++
			s.mu.Unlock()
		}
	}
}

// NextHeartbeatDelay returns the next sleep duration the heartbeat loop will
// pick: HeartbeatInterval ± random jitter bounded by HeartbeatJitterFraction.
// Exposed so tests can verify jitter bounds without sleeping for 30s.
func (s *Spoke) NextHeartbeatDelay() time.Duration { return s.nextHeartbeatDelay() }

// nextHeartbeatDelay returns interval ± random jitter in [0, jitter*interval].
func (s *Spoke) nextHeartbeatDelay() time.Duration {
	base := s.cfg.HeartbeatInterval
	jf := s.cfg.HeartbeatJitterFraction
	if jf <= 0 {
		return base
	}
	// Random offset in (-jf*base, +jf*base).
	maxOffset := int64(float64(base) * jf)
	if maxOffset <= 0 {
		return base
	}
	n, err := rand.Int(rand.Reader, big.NewInt(2*maxOffset+1))
	if err != nil {
		return base
	}
	offset := n.Int64() - maxOffset
	d := base + time.Duration(offset)
	if d < 0 {
		d = base
	}
	return d
}

func (s *Spoke) hubURL(path string) (string, error) {
	base := strings.TrimRight(s.cfg.HubURL, "/")
	u, err := url.Parse(base + path)
	if err != nil {
		return "", err
	}
	return u.String(), nil
}

func (s *Spoke) postJSON(ctx context.Context, path string, body any) (*http.Response, error) {
	u, err := s.hubURL(path)
	if err != nil {
		return nil, err
	}
	buf, err := json.Marshal(body)
	if err != nil {
		return nil, err
	}
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, u, bytes.NewReader(buf))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", "application/json")
	return s.cfg.HTTPClient.Do(req)
}

// federationRegisterRequest mirrors the hub-side request shape. Defined here
// to keep the federation package self-contained — the hub side
// (cli/internal/server/federation_hub.go) declares its own equivalent struct
// against the same wire contract.
type federationRegisterRequest struct {
	NodeID               string   `json:"node_id"`
	IdentityFingerprint  string   `json:"identity_fingerprint,omitempty"`
	Name                 string   `json:"name"`
	URL                  string   `json:"url"`
	DDxVersion           string   `json:"ddx_version"`
	SchemaVersion        string   `json:"schema_version"`
	GraphQLSchemaVersion string   `json:"graphql_schema_version,omitempty"`
	Capabilities         []string `json:"capabilities,omitempty"`
}
